class Litte{
   PVector location;
   PVector velocity;
   PVector acceleration;
   float mass;
   Litte(float m,float x,float y){
     mass=m;
     location=new PVector(x,y);
     velocity=new PVector(0,0);
     acceleration=new PVector(0,0);
   }

   void applyForce(PVector force){     
     acceleration.add(force.div(mass));
   }

   void update(){
     velocity.add(acceleration);
     location.add(velocity);
     acceleration.mult(0);
   }

   void display(){
     if(mass<=0){
       return;
     }

       fill(100);
       stroke(127);
       strokeWeight(2);
       ellipse(location.x,location.y,mass*10,mass*10);  
   }   
   //边界检测
   void collidingedge(){
     if(location.x<=mass*10){
       velocity.x=velocity.x*(-1);
       location.x=mass*10;
     }else if(location.x>=width-mass){
       velocity.x=velocity.x*(-1);
       location.x=width-mass*10;
     }
     if(location.y>=height-mass*10){
       velocity.y*=(-1);
       location.y=height-mass*10;
     }else if(location.y<=mass*10){
       velocity.y*=(-1);
       location.y=mass*10;
     }   
  }

}
