class Cleaner{
  PVector location;
  Cleaner(PVector loc){
    location=loc.get();
  }

  void display(){
    fill(200);
    stroke(188);
    arc(location.x,location.y,200,200,radians(30),radians(150), PIE);
  }

  PVector attract(Litte other){
    PVector force=PVector.sub(this.location,other.location);
    force.normalize();
    return force;
  }














}
