class Ocean {
  float x, y, w, h;
  float c;

  Ocean(float x_, float y_, float w_, float h_, float c_) {
    x = x_;
    y = y_;
    w = w_;
    h = h_;
    c = c_;
  }

  // 判断Litter是否在Ocean内
  boolean contains(Litte m) {
    PVector pos = m.location;
    return pos.x > x && pos.x < x + w && pos.y > y && pos.y < y + h;
  }

  PVector drag(Litte m) {
    float speed = m.velocity.mag();
    float dragMag = c * pow(speed, 2);
    PVector dragforce = m.velocity.copy();
    dragforce.normalize();
    dragforce.mult(-1);
    dragforce.mult(dragMag);
    return dragforce;
  }
}
