class Particle{
  PVector location;
  PVector acceleration;
  PVector velocity;
  float lifeSpan;
  float mass=1;
  PImage image;

  Particle(PVector originLoc,PImage img){
    acceleration=new PVector(0,0);
    location=originLoc.get();
    velocity=new PVector(random(-1,1),random(-2,0));
    lifeSpan=255.0;
    image=img;
  }

  void run(){
    update();
    render();
  }

  void update(){
    velocity.add(acceleration);
    location.add(velocity);
    acceleration.mult(0);
    lifeSpan-=2.0;
  }

  void render(){
    imageMode(CENTER);
    tint(lifeSpan);
    image(image,location.x,location.y,32,32);  
  }
  // void display(){
    // stroke(0,lifeSpan);
    // fill(127,lifeSpan);
    // ellipse(location.x,location.y,12,12);

  // }  
  void applyForce(PVector force){
    acceleration.add(force.div(mass));
  }

  boolean isDead(){
    if(lifeSpan<0){
      return true;
    }else{
      return false;
    }    
  }


}
