class ParticlesSystem{
  ArrayList<Particle> particles;
  PVector origin;
  PImage[] images;
  ParticlesSystem(PVector location,PImage[] im){
    origin=location.get();
    particles=new ArrayList<Particle>();
    images=im;
  }

  void addParticle(PVector present){
    int r=(int)random(images.length);
    particles.add(new Particle(present,images[r]));
  }

  void applyForce(PVector force){
    for(Particle p: particles){
      p.applyForce(force);
    }  
  }

  void run(){
    for(int i=particles.size()-1;i>=0;i--){
      Particle p=particles.get(i);
      if(p.isDead()){
        particles.remove(i);
      }
      p.run();  
    }
  }
}
