Star star[];
Litte litter[];
Ocean ocean;
Cleaner cleaner;
ParticlesSystem ps;
ParticlesSystem psStar;
PVector litterPos[];
PVector[] particlePos;
PVector[] starPos;
PImage[] images;
PImage[] imagesStar;
PImage tree;
float a=0;
float ystart=100.0;
float inc=0.1;
float mindistance=100f;
float startTime;
int count=0;
boolean canEmit;
boolean ismouse;
boolean slide;
boolean newScreen;

void setup(){
  size(600,600);
  star=new Star[3];
  litter=new Litte[10];
  ocean=new Ocean(0,height*2/3,width,height/3,0.1);
  cleaner=new Cleaner(new PVector(width/2,0));
  ps=new ParticlesSystem(new PVector(width/2,height/2),images);
  psStar=new ParticlesSystem(new PVector(0,height/2),imagesStar);

  tree=loadImage("pictures/seanson.png");
  litterPos=new PVector[20];
  initLitter();  
  images=new PImage[3];
  images[0]=loadImage("pictures/good.png");
  images[1]=loadImage("pictures/corona.png");
  images[2]=loadImage("pictures/particle.png");
  imagesStar=new PImage[3];
  imagesStar[0]=loadImage("pictures/good.png");
  imagesStar[1]=loadImage("pictures/starS.png");
  imagesStar[2]=loadImage("pictures/reflection.png");
  psStar=new ParticlesSystem(new PVector(0,height/2),imagesStar);
  ps=new ParticlesSystem(new PVector(width/2,height/2),images);

  particlePos=new PVector[20];
  for(int i=0;i<20;i++){
    float x=random(10,width);
    float y=random(200,height);
    particlePos[i]=new PVector(x,y);
  }
  starPos=new PVector[10];
  for(int i=0;i<10;i++){
    float x=random(50,width-50);
    float y=random(50,height/3);
    starPos[i]=new PVector(x+10,y);
  }

  canEmit=false;
  slide=false;
  newScreen=false;

}

void draw(){
  isMouse();
  isEmit();
  isNew();
  if(!slide){
    liquid();
    cleanerRotate();
    if(!ismouse){
      litterMoveDown();
    }else{
      litterMoveUp();
    }
  }
  if(slide&&ismouse&&!newScreen){     
    background(0);
    if(canEmit&&millis()-startTime<=5000){
        wish();
      }else if(millis()-startTime>5000){
        blendMode(BLEND);
      }
    }

  if(newScreen&&ismouse&&slide){
      noLitter();
    }

}

void isMouse(){
  if(mouseButton==LEFT){
    ismouse=true;
  }
}

void isEmit(){
  if(keyPressed && key == 'w' || key == 'W'&&!canEmit){
    if(startTime==0){
      startTime=millis();
    }
    canEmit=true;
  }
}

void isNew(){
  if(keyPressed && key == 'n' || key == 'N'){
    newScreen=true;
  }
}

void liquid(){
  beginShape();
  background(128,128,128);
  stroke(150);
  fill(102,153,204,100); 
  vertex(0, height);  // 左下角点
  for (float x = 0; x < width; x += 10){
    float y = height*2/3 + sin(x * 0.01 + ystart) * 10;  // 使用sin函数计算y坐标
    vertex(x, y);  // 添加顶点
  }
  vertex(width, height);  // 右下角点
  ystart += inc; 
  endShape(CLOSE);
}

void noLitter(){
  background(255);
  image(tree,0,0);
  stroke(200);
  fill(173,216,230);  
  beginShape();
  vertex(0, height);  // 左下角点
  for (float x = 0; x < width; x += 10){
    float y = height*3/4 + sin(x * 0.01 + ystart) * 10;  // 使用sin函数计算y坐标
    vertex(x, y);  // 添加顶点
  }
  vertex(width, height);// 右下角点
  ystart += inc;
  endShape(CLOSE);
}

void initLitter(){
 for(int i=0;i<20;i++){
    float x=random(0,width);
    float y=random(1*height/3,2*height/3);
    litterPos[i]=new PVector(x,y);
  }
  for(int j=0;j<10;j++){
    int r=(int)random(0,litterPos.length);
    litter[j]=new Litte(2,litterPos[r].x,litterPos[r].y);
  }
}

void litterMoveDown(){
  for(int j=0;j<10;j++){
    if(ocean.contains(litter[j])){
      PVector drag=ocean.drag(litter[j]);
      litter[j].applyForce(drag);
    }
    litter[j].applyForce(new PVector(0,0.1*litter[j].mass));
    litter[j].update();
    litter[j].display();
  }
}

void litterMoveUp(){
  for(int j=0;j<litter.length;j++){
    float dis=dist(litter[j].location.x,litter[j].location.y,cleaner.location.x,cleaner.location.y);
    if(dis<=mindistance){
      litter[j].mass=0;
      count++;
      if(count==litter.length){
        slide=true;
      }
    }
    if(ocean.contains(litter[j])){
      PVector drag=ocean.drag(litter[j]);
      litter[j].applyForce(drag);
    }
    PVector gra=new PVector(0,0.1*litter[j].mass);
    litter[j].applyForce(gra);
    PVector attraction=cleaner.attract(litter[j]).mult(0.3);
    litter[j].applyForce(attraction);
    litter[j].update();
    litter[j].display();
  }
}

void cleanerRotate(){
  pushMatrix();
  translate(width/2,0);
  fill(200);
  stroke(188);
  float angel=sin(a)*PI/4;
  rotate(angel);
  arc(0,0,200,200,radians(30),radians(150), PIE);
  popMatrix();
  a+=0.1;
}

void wish(){  
  background(0);
  blendMode(ADD);
  PVector gra=new PVector(0,-0.2);
    int r=(int)random(0,particlePos.length);
    for(int j=0;j<5;j++){
      ps.addParticle(particlePos[r]);
    }
  ps.applyForce(gra);
  ps.run();
  PVector graF=new PVector(-0.2,-0.2);
  int R=(int)random(0,starPos.length);
  psStar.addParticle(starPos[R]);
  psStar.applyForce(graF);
  psStar.run();
}
